                            'db' => $db,
                            'table' => $table,
                            'event' => $event,
                            'has_privilege' => Util::currentUserHasPrivilege('EVENT', $db),
                            'sql_drop' => $sqlDrop,
                            'row_class' => '',
                        ])
                    );
