public static function mb_convert_case($s, $mode, $encoding = null)
{
    $s = (string) $s;
    if ('' === $s) {
        return '';
    }

    $encoding = self::getEncoding($encoding);

    if ('UTF-8' === $encoding) {
        $encoding = null;
        if (!preg_match('//u', $s)) {
