            }

            static $lower = null;
            if (null === $lower) {
                $lower = self::getData('lowerCase');
            }
            $map = $lower;
        }

        static $ulenMask = ["\xC0" => 2, "\xD0" => 2, "\xE0" => 3, "\xF0" => 4];

        $i = 0;
        $len = \strlen($s);

        while ($i < $len) {
            $ulen = $s[$i] < "\x80" ? 1 : $ulenMask[$s[$i] & "\xF0"];
